std::map<std::string, int> count_unique_words(const std::string& str) {
    std::unordered_set<std::string> unique_words;
    std::map<std::string, int> word_count;

    std::string word;
    std::regex re("\\W+");
    std::sregex_token_iterator it(str.begin(), str.end(), re, -1);
    std::sregex_token_iterator end;

    for (; it != end; ++it) {
        word = *it;
        for (char& c : word) {
            c = std::tolower(c);
        }

        if (word_count.find(word) != word_count.end()) {
            ++word_count[word];
        } else {
            word_count[word] = 1;
            unique_words.insert(word);
        }
    }

    std::cout << "Count of unique words: " << unique_words.size() << std::endl;
    std::cout << "Breakdown of each word with its occurrence:" << std::endl;

    for (const auto& pair : word_count) {
        std::cout << pair.first << ": " << pair.second << std::endl;
    }

    return word_count;
}

