#include <string>
#include <unordered_map>

class Log {
public:
    std::string timestamp;
    std::string content;

    Log(const std::string& timestamp, const std::string& content) 
        : timestamp(timestamp), content(content) {}
};

class LogSorter {
private:
    std::deque<Log> logDeque;
    std::unordered_map<std::string, std::string> mergedLogs;

public:
    void addLog(const Log& log) {
        auto it = mergedLogs.find(log.timestamp);
        if (it != mergedLogs.end()) {
            it->second += log.content;
        } else {
            mergedLogs[log.timestamp] = log.content;
        }
    }

    void sortLogs() {
        logDeque.clear();
        for (const auto& pair : mergedLogs) {
            logDeque.push_back(Log(pair.first, pair.second));
        }
        while (!logDeque.empty()) {
            Log front = logDeque.front();
            logDeque.pop_front();
            for (const auto& pair : mergedLogs) {
                if (pair.first > front.timestamp) {
                    logDeque.push_front(Log(pair.first, pair.second));
                }
            }
        }
    }

    void printLogs() const {
        for (const auto& log : logDeque) {
            std::cout << log.timestamp << ": " << log.content << std::endl;
        }
    }
};

int main() {
    LogSorter sorter;
    sorter.addLog(Log("2022-01-01 12:00:00", "INFO: User logged in"));
    sorter.addLog(Log("2022-01-01 12:00:00", "WARNING: Low disk space"));
    sorter.addLog(Log("2022-01-01 12:05:00", "INFO: User performed action"));
    sorter.addLog(Log("2022-01-01 12:00:00", "DEBUG: Debug message"));

    sorter.sortLogs();
    sorter.printLogs();

    return 0;
}
