public class Main {
    public static void main(String[] args) {
        String text = "The quick brown fox jumps over the lazy dog";
        String[] words = {"fox", "dog"};

        Map<String, Integer> anagramOccurrences = detectAnagramOccurrences(text, words);
        System.out.println(anagramOccurrences);
    }

    public static Map<String, Integer> detectAnagramOccurrences(String text, String[] words) {
        // Convert text to lowercase and split it into words
        String[] textWords = text.toLowerCase().split("\\s+");

        // Create a map to store the frequency of each word
        Map<String, Long> wordFrequency = new HashMap<>();

        // Create a map to store the frequency of each word's sorted characters
        Map<String, Long> sortedWordFrequency = new HashMap<>();

        // Count the frequency of each word and its sorted characters
        for (String word : words) {
            wordFrequency.put(word, wordFrequency.getOrDefault(word, 0L) + 1);
            String sortedWord = String.valueOf(word.chars().sorted().toArray());
            sortedWordFrequency.put(sortedWord, sortedWordFrequency.getOrDefault(sortedWord, 0L) + 1);
        }

        // Count the frequency of each word's sorted characters in the text
        for (String word : textWords) {
            if (wordFrequency.containsKey(word)) {
                String sortedWord = String.valueOf(word.chars().sorted().toArray());
                sortedWordFrequency.put(sortedWord, sortedWordFrequency.get(sortedWord) + 1);
            }
        }

        // Count the occurrences of each word as an anagram
        Map<String, Integer> anagramOccurrences = new HashMap<>();
        for (String word : wordFrequency.keySet()) {
            String sortedWord = String.valueOf(word.chars().sorted().toArray());
            anagramOccurrences.put(word, (int) wordFrequency.get(word) - sortedWordFrequency.getOrDefault(sortedWord, 0L));
        }

        return anagramOccurrences;
    }
}
