package main

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"strings"
)

type LogEntry struct {
	Time    string
	Message string
}

type LogBuffer struct {
	Entries []LogEntry
	Buffer   *bufio.Reader
}

func NewLogBuffer(filePath string) (*LogBuffer, error) {
	buffer := &LogBuffer{
		Buffer: bufio.NewReader(os.OpenFile(filePath, os.O_RDONLY, 0666)),
	}

	var entry LogEntry
	for {
		line, err := buffer.Buffer.ReadString('\n')
		if err != nil {
			break
		}
		parts := strings.Split(line, " - ")
		if len(parts) == 2 {
			time, message := parts[0], parts[1]
			entry.Time = time
			entry.Message = message
			buffer.Entries = append(buffer.Entries, entry)
		}
	}

	return buffer, nil
}

func (b *LogBuffer) SearchForErrors(pattern string) map[string]int {
	errorReport := make(map[string]int)

	for _, entry := range b.Entries {
		if strings.Contains(entry.Message, pattern) {
			count, ok := errorReport[pattern]
			if ok {
				errorReport[pattern] = count + 1
			} else {
				errorReport[pattern] = 1
			}
		}
	}

	return errorReport
}

func processLogFile(filePath string) map[string]int {
	buffer, err := NewLogBuffer(filePath)
	if err != nil {
		fmt.Println(err)
		return nil
	}
	defer func() {
		if err := buffer.Buffer.Close(); err != nil {
			fmt.Println(err)
		}
	}()

	return buffer.SearchForErrors("ERROR")
}

func main() {
	logReport := processLogFile("path_to_your_log_file.log")
	for pattern, count := range logReport {
		fmt.Printf("Error Pattern: %s, Frequency: %d\n", pattern, count)
	}
}
