import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.PriorityQueue;

class Meeting {
    String name;
    int urgency;

    public Meeting(String name, int urgency) {
        this.name = name;
        this.urgency = urgency;
    }
}

public class Main {
    public static ArrayList<Meeting> organizeMeetings(ArrayList<Meeting> meetings) {
        Collections.sort(meetings, new Comparator<Meeting>() {
            @Override
            public int compare(Meeting m1, Meeting m2) {
                return Integer.compare(m2.urgency, m1.urgency);
            }
        });

        ArrayList<Meeting> processedMeetings = new ArrayList<>();
        PriorityQueue<Meeting> pq = new PriorityQueue<>(Collections.reverseOrder());

        for (Meeting meeting : meetings) {
            pq.add(meeting);
        }

        while (!pq.isEmpty()) {
            Meeting currentMeeting = pq.poll();
            processedMeetings.add(currentMeeting);
        }

        return processedMeetings;
    }

    public static void main(String[] args) {
        ArrayList<Meeting> meetings = new ArrayList<>();
        meetings.add(new Meeting("Meeting 1", 3));
        meetings.add(new Meeting("Meeting 2", 1));
        meetings.add(new Meeting("Meeting 3", 2));
        meetings.add(new Meeting("Meeting 4", 4));

        ArrayList<Meeting> processedMeetings = organizeMeetings(meetings);

        for (Meeting meeting : processedMeetings) {
            System.out.println("(" + meeting.name + ", " + meeting.urgency + ")");
        }
    }
